   567|function assertSafePatchPath(repoPath: string): void {
   568|  const normalized = repoPath.replace(/^\/+/, '').replace(/\\/g, '/');
   569|  if (!normalized || normalized.includes('..') || path.isAbsolute(repoPath)) {
   570|    throw new Error(`Unsafe patch path rejected: ${repoPath}`);
   571|  }
   572|  const lower = normalized.toLowerCase();
   573|  if (lower.startsWith('.rork/') || lower.startsWith('.git/') || lower.startsWith('logs/') || lower.startsWith('tmp/')) {
   574|    throw new Error(`Patch path is outside IVX code allowlist: ${repoPath}`);
   575|  }
   576|  if (lower === '.env' || lower.startsWith('.env.') || lower.includes('/.env') || lower.includes('secret') || lower.endsWith('.pem') || lower.endsWith('.key')) {
